if (match ov {
        Some(e1) => r1.is_some() && e1@ == r1.get_Some_0()@,
        None => r1.is_None(),
    }) && (match ov {
        Some(e1) => r2.is_some() && e1@ == r2.get_Some_0()@,
        None => r2.is_None(),
    }) {
        match ov {
            Some(e1) => {
                assert(r1 is Some);
                assert(r2 is Some);
                assert(e1@ == r1->Some_0@);
                assert(e1@ == r2->Some_0@);
                assert(r1->Some_0@ =~= r2->Some_0@);
                assert(r1->Some_0 == r2->Some_0);
            }
            None => {
                assert(r1 is None);
                assert(r2 is None);
            }
        }
    }
